// Anthropic published rates per million tokens (USD → cents, multiply by 100):
// Claude Sonnet 4.5:  $3 input / $15 output → 300 / 1500 cents per 1M tokens
// Claude Opus 4.7:    $15 input / $75 output
// Claude Haiku 4.5:   $0.25 input / $1.25 output
const rates = {
  'claude-sonnet-4-5':  { in: 300,  out: 1500 },
  'claude-sonnet-4-5-20250929': { in: 300, out: 1500 },
  'claude-opus-4-7':    { in: 1500, out: 7500 },
  'claude-haiku-4-5':   { in: 25,   out: 125 },
  'claude-haiku-4-5-20251001': { in: 25, out: 125 },
  // fallback for unknown models — assume Sonnet rates
  '_default':           { in: 300,  out: 1500 }
};
const rows = Array.isArray($input.item.json) ? $input.item.json : [];
let inTokens = 0, outTokens = 0, costCents = 0, callsCount = rows.length;
const byModel = {};
rows.forEach(function (r) {
  const ti = parseInt(r.tokens_input) || 0;
  const to = parseInt(r.tokens_output) || 0;
  const rate = rates[r.model] || rates._default;
  // cents per 1M tokens × tokens / 1,000,000
  const c = (ti * rate.in + to * rate.out) / 1000000;
  inTokens += ti; outTokens += to; costCents += c;
  if (r.model) byModel[r.model] = (byModel[r.model] || 0) + c;
});
const tracking_date = new Date(Date.now() - 86400000).toISOString().slice(0,10);
return { json: { row: { tracking_date, service_name: 'anthropic', spend_cents: Math.round(costCents), data_source: 'internal_log', usage_metrics: { calls: callsCount, tokens_input: inTokens, tokens_output: outTokens, by_model: byModel }, notes: 'Computed from agent_decisions table using published per-1M-token rates.' } } };

